### 8. Verification (Agent Test)
I'll write a test in `pkg/agent/agent_test.go` that:
1.  Registers a mock tool.
2.  Mocks the LLM to return a "ReAct" response.
3.  Verifies the agent correctly processes the thought and adds the tool observation to history.

```go
package agent

import (
	"context"
	"testing"
)

type MockLLM struct {
	Response string
}

func (m *MockLLM) Chat(ctx context.Context, messages []Message) (string, error) {
	return m.Response, nil
}

func TestAgentStep(t *testing.T) {
	reg := NewRegistry()
	reg.Register(&MockTool{}) // Registers 'echo'

	llm := &MockLLM{
		Response: `Thought: I will echo hello.
Action: echo("hello")`,
	}

	a := New(llm, reg)
	_, err := a.Step(context.Background(), "Start")
	if err != nil {
		t.Fatalf("Step failed: %v", err)
	}

	// Verify history
	// 1. user: Start
	// 2. assistant: Thought/Action
	// 3. user: Observation
	if len(a.History) != 3 {
		t.Fatalf("Expected 3 messages in history, got: %d", len(a.History))
	}

	obs := a.History[2].Content
	if obs != "Observation: \"hello\"" { // MockTool returns the arg as-is
		t.Errorf("Expected Observation: \"hello\", got: %s", obs)
	}
}
```

