### 3. Write the OpenRouter Test (Red Phase)
I'll write `pkg/provider/openrouter_test.go`. This test will simulate an OpenRouter server and check if the client correctly sends the JSON payload and parses the response.

```go
package provider

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestOpenRouterChat(t *testing.T) {
	// 1. Setup a mock server
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Verify headers
		if r.Header.Get("Authorization") != "Bearer test-key" {
			t.Errorf("Expected Auth header 'Bearer test-key', got: %s", r.Header.Get("Authorization"))
		}

		// Return a mock response
		resp := map[string]interface{}{
			"choices": []map[string]interface{}{
				{
					"message": map[string]interface{}{
						"content": "Thought: I see the files.\nAction: ls({\"path\": \".\"})",
					},
				},
			},
		}
		json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	// 2. Initialize the client (we need to implement this next)
	client := NewOpenRouter("test-key", "google/gemini-2.0-flash-001")
	client.BaseURL = server.URL // Override for testing

	messages := []Message{
		{Role: "user", Content: "Hello"},
	}

	// 3. Call Chat
	res, err := client.Chat(context.Background(), messages)
	if err != nil {
		t.Fatalf("Chat failed: %v", err)
	}

	expected := "Thought: I see the files.\nAction: ls({\"path\": \".\"})"
	if res != expected {
		t.Errorf("Expected response '%s', got: '%s'", expected, res)
	}
}
```

