### 4. Implementation (Green Phase)
Now I'll implement `Save` and `Load` in `pkg/agent/agent.go`. 

I'll also define a `State` struct that maps to the JSON format. This allows us to easily add more data (like usage/token counts) in the future.

```go
package agent

import (
	"encoding/json"
	"os"
	"github.com/user/armage/pkg/provider"
)

type State struct {
	History []provider.Message `json:"history"`
}

// Save persists the agent's history to disk.
func (a *Agent) Save(path string) error {
	state := State{History: a.History}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0644)
}

// Load restores the agent's history from disk.
func (a *Agent) Load(path string) error {
	data, err := os.ReadFile(path)
	if err != nil {
		return err
	}
	var state State
	if err := json.Unmarshal(data, &state); err != nil {
		return err
	}
	a.History = state.History
	return nil
}
