func TestIntegrationReAct(t *testing.T) {
	apiKey := os.Getenv("OPENROUTER_API_KEY")
	if apiKey == "" {
		t.Skip("Skipping integration test: OPENROUTER_API_KEY not set")
	}

	// 1. Setup with a FREE model
	model := "google/gemma-2-9b-it:free"
	llm := provider.NewOpenRouter(apiKey, model)
	reg := NewRegistry()
	reg.Register(&ShellTool{})

	a := New(llm, reg)
	a.AddSystemPrompt("You are Armage. Follow ReAct: Thought then Action: shell(...)")

	// 2. Ask a simple question that requires a tool
	ctx := context.Background()
	_, err := a.Step(ctx, "List the files in the current directory.")
	if err != nil {
		t.Fatalf("Agent step failed: %v", err)
	}

	// 3. Verify the loop worked
	// Expecting:
	// 1. User: List the files...
	// 2. Assistant: Thought + Action: shell("ls")
	// 3. User: Observation: (ls output)
	foundAction := false
	foundObservation := false

	for _, msg := range a.History {
		if msg.Role == "assistant" && strings.Contains(msg.Content, "Action: shell") {
			foundAction = true
		}
		if msg.Role == "user" && strings.Contains(msg.Content, "Observation:") {
			foundObservation = true
		}
	}

	if !foundAction {
		t.Errorf("Agent did not produce a shell action. History: %+v", a.History)
	}
	if !foundObservation {
		t.Errorf("Agent did not receive a tool observation. History: %+v", a.History)
	}
}
