package main

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/bubbles/textinput"
	"github.com/charmbracelet/bubbles/viewport"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
	"github.com/user/armage/pkg/agent"
)

var (
	titleStyle = lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("#7D56F4")).
			Padding(0, 1)
	historyStyle = lipgloss.NewStyle().
			Border(lipgloss.RoundedBorder()).
			BorderForeground(lipgloss.Color("62")).
			Padding(1, 2)
)

type model struct {
	agent    *agent.Agent
	history  []string
	input    textinput.Model
	viewport viewport.Model
	err      error
}

func initialModel(a *agent.Agent) model {
	ti := textinput.New()
	ti.Placeholder = "Ask Armage..."
	ti.Focus()
	ti.CharLimit = 256
	ti.Width = 40

	vp := viewport.New(80, 20)
	vp.SetContent("Welcome to Armage. Ready for commands.")

	return model{
		agent:    a,
		history:  []string{},
		input:    ti,
		viewport: vp,
	}
}

func (m model) Init() tea.Cmd {
	return textinput.Blink
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	var (
		tiCmd tea.Cmd
		vpCmd tea.Cmd
	)

	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch msg.Type {
		case tea.KeyCtrlC, tea.KeyEsc:
			return m, tea.Quit
		case tea.KeyEnter:
			val := m.input.Value()
			if val != "" {
				m.history = append(m.history, fmt.Sprintf("> %s", val))
				m.input.Reset()
				// TODO: Trigger agent step here
				m.viewport.SetContent(strings.Join(m.history, "\n"))
			}
		}

	case tea.WindowSizeMsg:
		m.viewport.Width = msg.Width
		m.viewport.Height = msg.Height - 6
	}

	m.input, tiCmd = m.input.Update(msg)
	m.viewport, vpCmd = m.viewport.Update(msg)
	return m, tea.Batch(tiCmd, vpCmd)
}

func (m model) View() string {
	return fmt.Sprintf(
		"%s\n\n%s\n\n%s\n\n(ctrl+c to quit)",
		titleStyle.Render("ARMAGE AGENT"),
		historyStyle.Render(m.viewport.View()),
		m.input.View(),
	)
}

