### 4. Implementation (Green Phase)
Now I'll implement `WriteTool` in `pkg/agent/write_tool.go`. 

Following the `req.md` mandate, this tool will be **atomic**.
1.  **Write** to `[filename].tmp`.
2.  **Rename** `[filename].tmp` to `[filename]`.
This ensures that if the process is killed halfway (common in Termux), the original file isn't corrupted.

```go
package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

type WriteTool struct{}

type writeArgs struct {
	Path    string `json:"path"`
	Content string `json:"content"`
}

func (w *WriteTool) Name() string { return "write_file" }

func (w *WriteTool) Description() string {
	return "Writes content to a file. This is an atomic operation."
}

func (w *WriteTool) Execute(ctx context.Context, args string) (string, error) {
	var a writeArgs
	if err := json.Unmarshal([]byte(args), &a); err != nil {
		return "", fmt.Errorf("invalid arguments: %w", err)
	}

	// 1. Ensure directory exists
	dir := filepath.Dir(a.Path)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return "", err
	}

	// 2. Atomic write: Write to .tmp first
	tmpPath := a.Path + ".tmp"
	if err := os.WriteFile(tmpPath, []byte(a.Content), 0644); err != nil {
		return "", err
	}

	// 3. Move .tmp to target
	if err := os.Rename(tmpPath, a.Path); err != nil {
		return "", err
	}

	return fmt.Sprintf("Successfully wrote to %s", a.Path), nil
}
```

