### 4. Implementation (Green Phase)
Now I'll implement `SearchTool` in `pkg/agent/search_tool.go`. 

Since Termux has a pre-patched `grep`, I'll use it to perform the search. This is **robust** because Termux's `grep` is optimized for Android's Bionic library and handles symbolic links and file encodings correctly.

```go
package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os/exec"
)

type SearchTool struct{}

type searchArgs struct {
	Pattern string `json:"pattern"`
	Path    string `json:"path"`
}

func (s *SearchTool) Name() string { return "grep_search" }

func (s *SearchTool) Description() string {
	return "Searches for a regex pattern in files within a path. Returns matching lines with line numbers."
}

func (s *SearchTool) Execute(ctx context.Context, args string) (string, error) {
	var a searchArgs
	if err := json.Unmarshal([]byte(args), &a); err != nil {
		return "", fmt.Errorf("invalid arguments: %w", err)
	}

	if a.Path == "" {
		a.Path = "."
	}

	// Use grep -r (recursive) -n (line numbers) -I (ignore binary files)
	cmd := exec.CommandContext(ctx, "grep", "-rnI", a.Pattern, a.Path)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// grep returns status 1 if no matches found, which is a success in agent logic
		if cmd.ProcessState.ExitCode() == 1 {
			return "No matches found.", nil
		}
		return string(output), err
	}

	return string(output), nil
}
