I'll implement the **`DiffTool`** immediately. The integration test failure proved exactly why it's needed: the LLM struggled with escaping a full file in JSON and accidentally included the "1 | " line numbers in its output. 

A `diff_tool` (Search/Replace) is much more robust because the agent only has to send a small snippet of code.

### 1. Implement the `DiffTool` (Green Phase)

I'll create `pkg/agent/diff_tool.go`. It will:
1.  Read the target file.
2.  Find the **exact** match for the `find` string.
3.  Replace it with the `replace` string.
4.  Write the file back atomically.

```go
package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strings"
)

type DiffTool struct{}

type diffArgs struct {
	Path    string `json:"path"`
	Find    string `json:"find"`
	Replace string `json:"replace"`
}

func (d *DiffTool) Name() string { return "edit_file_diff" }

func (d *DiffTool) Description() string {
	return "Surgically updates a file. Provide the EXACT 'find' block and the 'replace' block."
}

func (d *DiffTool) Execute(ctx context.Context, args string) (string, error) {
	var a diffArgs
	if err := json.Unmarshal([]byte(args), &a); err != nil {
		return "", fmt.Errorf("invalid JSON for diff: %w", err)
	}

	content, err := os.ReadFile(a.Path)
	if err != nil {
		return "", err
	}

	if !strings.Contains(string(content), a.Find) {
		return "", fmt.Errorf("could not find the exact 'find' block in %s. Ensure whitespace and line endings match", a.Path)
	}

	newContent := strings.Replace(string(content), a.Find, a.Replace, 1)

	// Atomic write using our existing WriteTool logic
	tmpPath := a.Path + ".tmp"
	if err := os.WriteFile(tmpPath, []byte(newContent), 0644); err != nil {
		return "", err
	}
	if err := os.Rename(tmpPath, a.Path); err != nil {
		return "", err
	}

	return fmt.Sprintf("Successfully updated %s", a.Path), nil
}
```

